Set.Bottom:
(function() {
    var ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    //提交后台数据时执行的检查或附加数据处理
    ewa.DoPostBefore = function() {
        if (ewa.ext_running) {
            $Tip("提交中...");
            return false;
        }
        var code = getObj('#sms_code').val();
        if (!code) {
            $Tip('请输入验证码');
            return false;
        }
        if (code.length != 6) {
            $Tip('请输入6位验证码');
            return false;
        }

        var FP_UNID = ewa.FP_UNID;
        if (!FP_UNID) {
            $Tip('您还未获取验证码');
            return false;
        }

        if(!ewa.CheckValidAll()){
            return false;
        }

        var url = EWA.F.FOS["@SYS_FRAME_UNID"].Url;
        var u1 = new EWA_UrlClass();
        u1.SetUrl(url);
        u1.AddParameter("FP_UNID", FP_UNID);
        u1.AddParameter("sms_code",code);
        u1.AddParameter("MOBILE",getObj('#MOBILE').val());
        u1.AddParameter("ewa_ajax","json");
        u1.AddParameter("ewa_action","OnPagePost");
        var u = u1.GetUrl();
        $J(u, function(datas) {
            if(datas[0].result){
                $Tip(datas[0].result);
                return;
            }
            $Tip("OK");
            if(window.EWA_App){
                EWA_App.back();
            }else{
                EWA.OW.Load();
                if("@EWA_P_BEHAVIOR".toUpperCase().indexOf("RELOAD")>=0){
                    EWA.OW.PWin.EWA.F.FOS["@EWA_PARENT_FRAME"].Reload();
                }
                EWA.OW.Close();
            }
        });
        return false;
    };
    ewa.SmsValid = function(obj) {
        var text = $(obj).val();
        var phone = $('#EWA_FRAME_@SYS_FRAME_UNID #MOBILE').val();
        if (phone == '') {
            $Tip('请输入您的手机号');
            return;
        }

        $(obj).attr('t', text);
        $(obj).prop('disabled', true);
        $(obj).val("发送短信中...");

        var url = EWA.F.FOS["@SYS_FRAME_UNID"].Url;
        var u1 = new EWA_UrlClass();
        u1.SetUrl(url);
        u1.AddParameter("ewa_ajax","json");
        u1.AddParameter("ewa_action", "smsSendValidCode");
        u1.AddParameter("MOBILE", phone);
        var u = u1.GetUrl();

        var inc = 120;
        $J(u, function(datas) {
            if(datas[0].rst_type=="text"){
                alert(datas[0].result);
                $(obj).val(text);
                $(obj).prop('disabled', false);
                ewa.FP_UNID = null;
                return;
            }
            let rst=JSON.parse(datas[0].result);
            if (!rst.RST) {
                alert(rst.ERR);
                $(obj).val(text);
                $(obj).prop('disabled', false);
                ewa.FP_UNID = null;
                return;
            }
            ewa.FP_UNID = rst.FP_UNID;

            var timer = window.setInterval(function() {
                inc--;
                if (inc == 0) {
                    window.clearInterval(timer);
                    $(obj).val(text);
                    $(obj).prop('disabled', false);
                } else {
                    $(obj).val("已发送(" + inc + "s)");
                }
            }, 1000);

            $('#EWA_FRAME_@SYS_FRAME_UNID #sms_code')[0].focus();
        });
    };

    function getObj(exp) {
        return exp?$('#f_@sys_frame_unid').find(exp):$('#f_@sys_frame_unid');
    }

    function init() {
        getObj('.ewa-sms-valid-code-button').val('发送验证码');
    }
    init();
})();

Set.Sql:
select CRM_CUS_ID from adm_user where adm_id=@g_adm_id;

select count(1) dup_mobile from ADM_USER where ADM_MOBILE = @MOBILE and ADM_ID != @G_ADM_ID;

-- 检查是不是接受验证码的手机号
select count(1) code_right from WEB_USER_FPWD 
    where fp_unid=@fp_unid
		and FP_VALIDCODE = @sms_code
		and FP_REF_TABLE=@MOBILE
;

delete WEB_USER_FPWD where fp_unid=@fp_unid and @dup_mobile=0 and @code_right=1; 

UPDATE CRM_CUS SET 
	CRM_CUS_MOBILE = @MOBILE
WHERE CRM_CUS_ID  = @CRM_CUS_ID and @dup_mobile=0 and @code_right=1;

UPDATE ADM_USER SET 
	ADM_MOBILE = @MOBILE,
	ADM_mdate = @sys_date
WHERE ADM_ID = @G_ADM_ID and @dup_mobile=0 and @code_right=1;


INSERT INTO ADM_LOG(SUP_ID, ADM_ID, ADM_NAME, LOG_CONTENT, LOG_TYPE
    , LOG_TIME, LOG_PWD, LOG_REF, LOG_AGENT
    , LOG_IP, LOG_CONTEXT, LOG_ADMID)
SELECT ISNULL(SUP_ID,-1), ADM_ID, ISNULL(adm_name,'-') , '修改手机号码', 'CHG_MOBILE'
    , @sys_date, @MOBILE, @SYS_REMOTE_REFERER, @SYS_USER_AGENT
    , @SYS_REMOTEip, @SYS_CONTEXTPATH, ''
FROM ADM_USER WHERE ADM_ID = @G_ADM_ID and @dup_mobile=0 and @code_right=1;

select case when @dup_mobile=0 and @code_right=1 then '' else '更新失败' end result,'text' rst_type;

