            function  change_pic_method(obj) {
    if($(obj).attr('takephoto')){
        $(obj).attr('takephoto',null).val('拍照模式');
        $('.ewa-row-ADM_PHOTO1').hide();
        //不处理获取照片
        $('.ewa-row-ADM_PHOTO1 input[type=hidden]').attr('ewa_tag','');
