function createDefaultSign() {
    let ss = ["<div style='font-size: 12px; font-family: arial'><hr><div >"];
    ss.push("@ADM_NAME " + ("@ADM_NAME_EN" != "@ADM_NAME" ? "@ADM_NAME_EN" : ""));
    ss.push("@SUP_NAME");

    if ("@SUP_NAME_EN" && "@SUP_NAME_EN" != "@SUP_NAME") {
        ss.push("@SUP_NAME_EN");
    }
    ss.push("<b>Phone</b>: @ADM_MOBILE");
    ss.push("<b>Email</b>: @ADM_EMAIL");

    if ("@SUP_HTTP") {
        ss.push('<a href="@SUP_HTTP" target=_blank>@SUP_HTTP</a>');
    }

    return ss.join("</div><div>") + "</div>";


}
(function() {
    let ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    //提交后台数据时执行的检查或附加数据处理
    ewa.DoPostBefore = function() {
        let cfg = {};
        let fs = "SMTP_HOST,SMTP_PORT,SMTP_UID,SMTP_PWD".split(",");
        for (let i = 0; i < fs.length; i++) {
            let field = fs[i];
            cfg[field] = getObj("#" + field).val();
        }
        getObj("#SMTP_CFG").val(JSON.stringify(cfg));
        return true;
    };

    ewa.ReloadAfter = function() {
        if ("@EWA_P_BEHAVIOR".indexOf("CLOSE_SELF") < 0) {
            EWA.OW.Load();
            if ("@RELOAD_ITEM") {
                EWA.OW.PWin.EWA.F.FOS["@EWA_PARENT_FRAME"].itemReload("@RELOAD_ITEM");
            }
            EWA.OW.Close();
        }
    }
    ewa.ext_test = function() {
        let u = new EWA_UrlClass("@EWA.CP/back_admin/common/sendmail.jsp");
        let fs = "SMTP_HOST,SMTP_PORT,SMTP_UID,SMTP_PWD,SMTP_UID".split(",");
        let ns = "SMTP,PORT,USR,PWD,FROM".split(",");
        for (let i = 0; i < fs.length; i++) {
            let field = fs[i];
            u.AddParameter(ns[i], getObj("#" + field).val());
        }
        u.AddParameter('SUBJECT', '测试邮件');
        u.AddParameter('body', '<h1>测试邮件:)</h1>');

        window.open(u.GetUrl());
    }

    function getObj(exp) {
        return $('#f_@sys_frame_unid').find(exp);
    }

    function init() {
        $("#SMTP_PWD").attr("autocomplete", "new-password");

        if (!getObj("#EMAIL_SIGN").val()) {
            let sign = createDefaultSign();
            getObj("#EMAIL_SIGN").val(sign)
            setTimeout(function() {
               window.frames[0].document.body.innerHTML = sign;
            }, 501);
        }
    }
    init();
})();

