SELECT case when @G_SUP_ID='3' then isnull(SMTP_HOST,'smtp.exmail.qq.com') else SMTP_HOST end SMTP_HOST ,case when @G_SUP_ID='3' then isnull(SMTP_PORT,465) else SMTP_PORT end SMTP_PORT ,isnull(SMTP_UID,ADM_EMAIL) SMTP_UID ,SMTP_PWD FROM EMAIL_SMTP_CFG A RIGHT JOIN ADM_USER B ON A.ADM_ID=B.ADM_ID WHERE ((@CFG_UNID is null and b.ADM_ID = @G_ADM_ID) or (a.CFG_UNID=@CFG_UNID and a.SUP_ID = @G_SUP_ID and a.CFG_TAG=@CFG_TAG)) ;
