(function() {
    const ewa = EWA.F.FOS["@sys_frame_unid"];

    function getObj(exp) {
        if (exp) {
            return $('#f_@sys_frame_unid').find(exp);
        } else {
            return $('#f_@sys_frame_unid');
        }
    }

    ewa.callTriggerValidBefore = function(obj) {
        if (ewa._waitClock) {
            $Tip('请等待一段时间后再发送');
            return false;
        }

        let data = ewa.createPostData();
        var phone = data.ADM_MOBILE;

        if (!phone) {
            $Tip('enus' == EWA.LANG ? 'Please enter your phone number' : '请输入您的手机号');
            return false;
        }

        return true;
    };
    ewa.SmsValid = function(obj) {
        var text = $(obj).val();
        let data = ewa.CreatePostData();
        var phone = data.ADM_MOBILE;

        if (!phone) {
            $Tip('enus' == EWA.LANG ? 'Please enter your phone number' : '请输入您的手机号');
            return;
        }

        $(obj).attr('t', text);
        $(obj).prop('disabled', true);
        $(obj).val("发送短信中...");

        var url = ewa.Url;
        var u1 = new EWA_UrlClass();
        u1.SetUrl(url);
        u1.AddParameter("method", "smslogin_send");
        // u1.AddParameter("USR_MOBILE", phone);

        var u = u1.GetUrl();

        var inc = 90;
        $JP(u, data, function(rst) {
            if (!rst.RST) {
                if (rst.ERR.indexOf('.checkValidSildePuzzleError') > 0) {
                    eval(rst.ERR);
                } else {
                    alert(rst.ERR);
                }
                $(obj).val(text);
                $(obj).prop('disabled', false);
                ewa.FP_UNID = null;
                return;
            }
            ewa._waitClock = true;
            ewa.FP_UNID = rst.FP_UNID;

            var timer = window.setInterval(function() {
                inc--;
                if (inc == 0) {
                    window.clearInterval(timer);
                    $(obj).val(text);
                    $(obj).prop('disabled', false);
                    ewa._waitClock = false;
                } else {
                    $(obj).val("已发送(" + inc + "秒)");
                }
            }, 1000);

            $('#EWA_FRAME_@SYS_FRAME_UNID #sms_code')[0].focus();
        });
    };
    ewa.DoPostBefore = function() {
        var add_data = {};
        this.PostAddData = add_data;
        // ios接收apns消息的设备Token
        if (window.IOS_TOKEN) {
            // NSString *code=[NSString stringWithFormat:@"window.IOS_TOKEN = '%@';", token];
            // NSString *rst= [_mainWeb stringByEvaluatingJavaScriptFromString: code];
            add_data["IOS_TOKEN"] = IOS_TOKEN;
            // window.PLATEFORM 在 gyap app 时创建，ewa.plateform 在 ERP 创建
            add_data["plateform"] = window.PLATEFORM || this.plateform;
            add_data["appNmae"] = window.APP_NAME || this.appNmae;
            add_data["plateform_appNmae"] = add_data["plateform"] + '!' + add_data["appNmae"];
            console.log(add_data);
            // alert(IOS_TOKEN);
        }
        console.log(ewa.FP_UNID)
        if (!ewa.FP_UNID) {
            $Tip('请先获取短信验证码');
            return;
        }
        if (getObj('#sms_code').val().length != 6) {
            $Tip('请输入6位验证码');
            return;
        }

        //附加数据处理
        ewa.PostAddData = {
            FP_UNID: ewa.FP_UNID
        };
        return true;
    };
    ewa.loginFail = function() {
        var msg = EWA.F.FOS['@SYS_FRAME_UNID'].Resources['login_fail'].GetInfo();
        if (!msg) {
            msg = "用户名/密码错误";
        }
        $Tip(msg);
    };
    var u1 = new EWA_UrlClass(ewa.Url);
    $('#EWA_FRAME_@sys_frame_unid input[type=radio]').attr('onclick', 'changelanguage(this)');

    if (u1.GetParameter("app") && window.EWA_App) {
        EWA_App.Section.reShowRadios($(EWA_App.SECTION_SHOW));

        if (localStorage['APP2017']) {
            try {
                var s = JSON.parse(localStorage['APP2017']);
                $('#ADM_LID')[0].value = s.l;
                $('#ADM_PWD')[0].value = s.p;
            } catch (e) {
                console.log(e);
            }
        }
    }
    if (localStorage['PF_LANG']) {
        var lang = localStorage['PF_LANG'];
        var o = $('input[value="' + lang + '"]');
        if (o.length == 0) {
            console.log(lang);
            return;
        }
        o = o[0];
        if (!o.checked) {
            o.click();
        }
    }
})();

Set.Sql:
UPDATE adm_user SET adm_lip = @SYS_REMOTEIP , adm_ldate = @sys_date , adm_unid = isnull(adm_unid, @sys_unid) , IOS_TOKEN = isnull(@IOS_TOKEN, IOS_TOKEN) WHERE adm_lid = @adm_lid AND adm_pwd = @adm_pwd ;
SELECT min(EXT_ID) AS EXT_ID FROM SYS_EXT WHERE EXT_REF_TAG=@plateform_appNmae AND EXT_REF_ID = (select adm_id from adm_user where adm_lid = @adm_lid AND adm_pwd = @adm_pwd) AND EXT_DES = @IOS_TOKEN AND @IOS_TOKEN IS NOT NULL ;
UPDATE SYS_EXT SET EXT_MDATE = @sys_date WHERE EXT_ID=@EXT_ID AND @IOS_TOKEN IS NOT NULL;
INSERT INTO SYS_EXT (EXT_REF_ID, EXT_REF_TAG, EXT_DES, EXT_CDATE, EXT_TAG, EXT_GRP, SUP_ID, ADM_ID) SELECT ADM_ID, @plateform_appNmae, @IOS_TOKEN, @sys_date, @plateform, @appNmae, SUP_ID, ADM_ID FROM adm_user WHERE @plateform_appNmae IS NOT null AND @IOS_TOKEN IS NOT NULL AND adm_lid = @adm_lid AND adm_pwd = @adm_pwd AND @EXT_ID is null ;

-- -- 创建 adm_user 和 WEB_USER 的关联数据 -- INSERT INTO WEB_USER( USR_LID, USR_PWD, USR_NAME, USR_IDCARD , USR_TELE, USR_EMAIL, USR_QQ, USR_MSN, USR_ICQ, USR_MOBILE , USR_ADDR, USR_CDATE , USR_COMPANY, USR_FROM, USR_UNID, SUP_ID , USR_SCM_UID, USR_SCM_XML ) SELECT ADM_LID, ADM_PWD, ADM_NAME, ADM_IDCARD , ADM_TELE, ADM_EMAIL, ADM_QQ, ADM_MSN, ADM_ICQ, ADM_MOBILE , ADM_ADDR, GETDATE() , NULL, 'ADM_USER', ADM_UNID, A.SUP_ID , B.SUP_UNID, '创建来自 ADM_USER = ' + CAST(a.ADM_ID as varchar(30)) FROM ADM_USER A LEFT JOIN SUP_MAIN B ON A.SUP_ID = B.SUP_ID WHERE A.ADM_ID = @ADM_ID AND @USR_ID IS NULL --AUTO USR_ID ;
UPDATE ADM_USER SET WEB_USR_ID = @USR_ID FROM WEB_USER WHERE ADM_ID = @ADM_ID AND @USR_ID IS NOT NULL;
SELECT USR_ID, USR_NAME, USR_UNID FROM WEB_USER WHERE USR_ID = @USR_ID ;

Set.Bottom:
function loginSuccess() {
    var u1 = new EWA_UrlClass(EWA.F.FOS["@sys_frame_unid"].Url);
    if (u1.GetParameter("app") && window.EWA_App) {
        try {
            var ss = {
                l: $('#ADM_LID')[0].value,
                p: $('#ADM_PWD')[0].value
            };
            var s = JSON.stringify(ss);
            localStorage['APP2017'] = s;
        } catch (e) {}

        if (u1.GetParameter("FROM") == "group" && u1.GetParameter("GRP_ID")) {
            // 检查代理和团的关系
            u1.RemoveEwa();
            var url = "@EWA.CP/app-2017/index_new_home_simple.jsp?check_agent=yes&" + u1.GetParas();

            $J(url, function(rst) {
                if (!rst.RST) {
                    console.log(rst);
                    showAgentNoAcl(rst);
                    return;
                } else {
                    //App-2017 登录
                    app2017LoginSuccess(); //defined in app-2017/index.jsp
                }
            });
        } else {
            //App-2017 登录
            app2017LoginSuccess(); //defined in app-2017/index.jsp
        }
    } else {
        // pop_login_main defined in robert/index.jsp
        $('#pop_login_main').hide().html("successful!");
        window.is_pop_login = false;
    }
}

// 代理和指定的团无法操作
function showAgentNoAcl(rst) {
    var s = "<div class='tip'><div>" + rst.ERR + "</div>";
    if (rst.SUP && rst.SUP.SUP_UNID) {
        s += "<a href='gyap-agent-index.jsp?agunid=" + rst.SUP.SUP_UNID + "'><h1>转到您的操作系统</h1></a>";
        s += " <div style='font-size:12px'>" + rst.SUP.SUP_NAME + "</div>";
    }
    s += "</div>";
    $("#f_@SYS_FRAME_UNID").html(s);
}

function loginAppSuccess() {
    // please covered this function
}

function relogin() {
    //called by adm_user.frame.syschangepwd
    $('#login-main-frame div:eq(0)').show();

    $('#login-main-frame #ADM_PWD').val("");

    $('#login-main-frame div.changepwd').hide();
}

function changePwd() {
    alert(EWA.F.FOS["@SYS_FRAME_UNID"].Resources.CW1.GetInfo());
    if (window.EWA_App || 1) {
        var id = 'changepwd' + Math.random();

        var u1 = new EWA_UrlClass(EWA.F.FOS["@sys_frame_unid"].Url);
        u1.AddParameter("method", "changepwd");
        var u = u1.GetUrl();
        $('#login-main-frame').append("<div class='changepwd' id='" + id + "'></div>");
        $Install(u, id, function() {
            $('#login-main-frame div:eq(0)').hide();
        });
    } else {
        window.location.href = 'login_chpwd.jsp?changepwd=1';
    }
}

if (!window.changelanguage) {
    window.changelanguage = function(obj) {
        var u1 = new EWA_UrlClass(EWA.F.FOS["@sys_frame_unid"].Url);
        var url = u1.AddParameter('ewa_lang', obj.value);
        var parent = $('#f_@sys_frame_unid').parent();
        $Install(url, parent, function() {

        });
        localStorage['PF_LANG'] = obj.value;
    }
}
/**
 * 检查当前app的版本 在IOS/Android app中调用
 */
function checkAppVersion(plateform, appNmae, appVersion) {
    // alert(plateform + ", " + appNmae + ", " + appVersion);
    var ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    ewa.plateform = plateform;
    ewa.appNmae = appNmae;
    ewa.appVersion = appVersion;

    var u1 = new EWA_UrlClass(ewa.Url);
    u1.AddParameter("ewa_action", "CheckAppVersion");
    u1.AddParameter("ewa_ajax", "json");
    u1.AddParameter("EWA_JSON_FIELD_CASE", "upper");
    u1.AddParameter("APP_NAME", appNmae);
    var u = u1.GetUrl();
    $J1(u, function(rst) {
        if (rst.length == 0) {
            return;
        }
        for (var n in rst) {
            var d = rst[n]; //数据行
            if (n == 0 && d.BAS_TAG == appNmae + '_' + appVersion) {
                //当前版本
                return;
            }
        }
        var cur = rst[0];
        var cur_version = cur.BAS_TAG.replace(appNmae + '_', '') * 1;
        console.log('cur_version=' + cur_version);
        if (cur_version < appVersion * 1) {
            //记录的最大版本 < 当前版本
            return;
        }
        var name = cur.BAS_TAG_NAME;
        var msg = "<div><b>有新版本推出(" + name + ")</b></div>" + cur.BAS_TAG_HTML + "<div>点击是去更新</div>";
        var a = cur.BAS_TAG_MEMO; //链接地址
        $Confirm(msg, name, function() {
            window.open(a);
        });
    });
}

function init_login_robert() {

    setTimeout(function() {
        if ($('#w1').length > 0) {
            $('#w1').html(EWA.F.FOS["@SYS_FRAME_UNID"].Resources.CW.GetInfo());
            $('#w2').html(EWA.F.FOS["@SYS_FRAME_UNID"].Resources.CHPWD.GetInfo());
        }
    }, 101);


    var u1 = new EWA_UrlClass(EWA.F.FOS["@sys_frame_unid"].Url);
    $('#EWA_FRAME_@sys_frame_unid input[type=radio]').attr('onclick', 'changelanguage(this)');

    if (u1.GetParameter("app") && window.EWA_App) {
        EWA_App.Section.reShowRadios($(EWA_App.SECTION_SHOW));

        if (localStorage['APP2017']) {
            try {
                var s = JSON.parse(localStorage['APP2017']);
                $('#ADM_LID')[0].value = s.l;
                $('#ADM_PWD')[0].value = s.p;
            } catch (e) {
                console.log(e);
            }
        }
    } else {
        $X('ADM_LID').focus();
    }
    if (localStorage['PF_LANG']) {
        var lang = localStorage['PF_LANG'];
        var o = $('input[value="' + lang + '"]');
        if (o.length == 0) {
            console.log(lang);
            return;
        }
        o = o[0];
        if (!o.checked) {
            o.click();
        }
    }
}

EWA.F.FOS["@sys_frame_unid"].DoPostBefore = function() {
    var add_data = {};
    this.PostAddData = add_data;
    // ios接收apns消息的设备Token
    if (window.IOS_TOKEN) {
        // NSString *code=[NSString stringWithFormat:@"window.IOS_TOKEN = '%@';", token];
        // NSString *rst= [_mainWeb stringByEvaluatingJavaScriptFromString: code];
        add_data["IOS_TOKEN"] = IOS_TOKEN;
        // window.PLATEFORM 在 gyap app 时创建，ewa.plateform 在 ERP 创建
        add_data["plateform"] = window.PLATEFORM || this.plateform;
        add_data["appNmae"] = window.APP_NAME || this.appNmae;
        add_data["plateform_appNmae"] = add_data["plateform"] + '!' + add_data["appNmae"];
        console.log(add_data);

        // alert(IOS_TOKEN);
    }

    add_data["PWD1"] = $("#EWA_FRAME_@sys_frame_unid #ADM_PWD").val();
    return true;
};
EWA.F.FOS["@sys_frame_unid"].loginFail = function() {
    var msg = EWA.F.FOS['@SYS_FRAME_UNID'].Resources['login_fail'].GetInfo();
    if (!msg) {
        msg = "用户名/密码错误";
    }
    $Tip(msg);
};


init_login_robert();

